var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"……그래서 이렇게 꽁꽁 묶어 뒀다는 거군.","JPN":"……で、こうやってぐるぐるに縛っておいたというわけか。","ENG":"...So that's why they're all tied up.","TWN":"……所以才將他們五花大綁嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"너무 순식간에 벌어져서 말릴 틈도 없었어. 소대장으로서 면목이 없네.","JPN":"あまりにも一瞬のことで、止める暇もなかったわ。小隊長として面目ない。","ENG":"It all happened so fast that I didn't have time to stop it. I am sorry that I couldn’t stop it as a commander of the squad.","TWN":"事情發生得太突然，我根本來不及阻止。身為小隊長，我真是失職！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"PMC_SUMMER_NULL_NULL","text":{"KOREA":"말도 안 돼…. 주력은 전부 자리를 비웠다고 들었는데….","JPN":"あり得ねえ……主力はみんな席を外してるって……","ENG":"Impossible...! We were informed that all the core members were absent...","TWN":"怎麼會這樣…我聽說主要戰力不是都不在嗎…"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PMC_SUMMER_NULL_NULL","text":{"KOREA":"대장, 이제 어쩌죠?","JPN":"隊長、どうしますか？","ENG":"Captain, what's our plan now?","TWN":"隊長，這下怎麼辦才好？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":{"char_id":"PMC_SUMMER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"PMC_SUMMER_NULL_NULL","text":{"KOREA":"관리국 지시를 이행 못했다고 알려지면 저희 평판도 박살나는 거 아니에요?","JPN":"管理局の指示を履行できなかったことが広まったら、俺らの評判もガタ落なんじゃないですか？","ENG":"If word gets out that we failed a request from the Administration, won't our reputation plummet to the ground?","TWN":"萬一被人知道我們無法完成管理局的指示，那一定會得到負評的啦！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"큭! 아니까 가만히 있어!","JPN":"くっ！　わかってるからじっとしてろ！","ENG":"Kgh! I know that! Lemme think!","TWN":"唔！我知道啦，先稍安勿躁！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PMC_SUMMER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L15_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"자, 오르카. 어서 저 아저씨들에게 사과해.","JPN":"はい、オルカ。早くあのおじさんたちに謝って。","ENG":"Okay, Orca. Go say sorry to the soldiers.","TWN":"奧爾卡，快點和叔叔們道歉。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"미안.","JPN":"ごめん。","ENG":"Sorry.","TWN":"搜哩。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"제대로 사과 안 하면 오늘 간식은 없어.","JPN":"ちゃんと謝らないと、今日のおやつはないわよ。","ENG":"If you don't apologize properly, there will be no snacks today.","TWN":"你再不好好道歉的話，今天就沒零食吃囉！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"죄송하다요.","JPN":"ごめん、です。","ENG":"I'm sorry.","TWN":"對不起嘛。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L20_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"빌어먹을! 이것들이 사람을 놀리나!","JPN":"くそ！　からかってんのか！","ENG":"Dammit! Stop messing around with us!","TWN":"可惡！是在玩我們嗎！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L21_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"너! 네가 이 회사 사장이지! 직원들 관리를 대체 어떻게 하는 거야!","JPN":"お前！　お前がこの会社の社長だろ！　社員の管理がなってねえじゃねえか！","ENG":"You! Aren't you the boss of this company?! How the hell are you managing your employees, huh?!","TWN":"你！你是這間公司的老闆吧！你是怎麼管理你的員工的！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"갑자기 들이닥쳐서 무기를 휘두른 자들이 할 말은 아니지 않나?","JPN":"いきなり押し寄せてきて暴力を振るった者の言う台詞ではないのでは？","ENG":"That's not a word that someone who just raided my business while armed can say.","TWN":"這麼說不對吧？是誰先突然拿著武器衝進來的？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"그러고 보니 델타 세븐도 이런 식으로 습격 당했다지.","JPN":"そういえば、デルタセブンもこんな風に襲撃されたらしいな。","ENG":"Come to think of it, Delta Seven was also raided like this.","TWN":"我看第七三角洲部隊也是像這樣被偷襲的吧？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"뭐, 뭐야? 지금 우리가 뭐 테러리스트라도 된다는 거냐?","JPN":"な、なんだ？　今、俺らをテロリスト扱いしてんのかよ？","ENG":"W-what? Are you implying that we're terrorists or something?","TWN":"搞，搞什麼？現在是把我們當成是恐怖份子嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그보다 더 심하죠. 우리 직원들에게 물리적 • 정신적 상해를 입혔지 않습니까.","JPN":"それよりひどいです。うちの社員に物理的・精神的被害を与えたではありませんか。","ENG":"You are worse than that. You and your men inflicted both physical and emotional distress to our employees.","TWN":"是比恐怖份子更過分才對。不只破壞我們公司，還害員工的心理受創。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"여기 찰리 씨를 보시죠.","JPN":"ここにいるチャーリーさんを見てください。","ENG":"Just look at Charlie over here.","TWN":"看看這位查理先生。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"우리 회사 최고의 수다쟁이가 충격을 받은 나머지 말 한마디 제대로 못하고 있습니다.","JPN":"会社一のおしゃべりが、あまりの衝撃に一言も話せずにいます。","ENG":"He's our chatterbox, but he's dumbfounded and left speechless.","TWN":"他原本在我們公司裡是話最多的，結果因為受到驚嚇，現在連一句話都說不好。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"흑흑. 너무 무서웠어요.","JPN":"しくしく。すごく怖かったんです。","ENG":"*Sob* I was so scared.","TWN":"嗚嗚，人家好怕。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"웃기지 마! 내 부하는 저 아저씨 주먹에 턱이 날아갈 뻔했다고!","JPN":"ふざけんな！　俺の部下はあのおっさんの拳で顎がふっ飛びそうになったんだぞ！","ENG":"Don’t make me laugh! My jaw almost got dislocated from his punching!","TWN":"聽你在胡扯！我手下的下巴差點被他的拳頭給打歪欸！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L36_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"샤오린 양은 그만하라고 눈물로 호소했는데도 들어 주지 않았다더군요.","JPN":"シャオリンさんは、やめてと涙ながらに訴えたにも関わらず、聞いてもらえなかったと。","ENG":"Even Xiao Lin begged you to stop with tears, but you refused.","TWN":"然後曉琳哭著求你們住手，你們也當作耳邊風一樣。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"우리 모두 사이 좋게 지내요. 네?","JPN":"みんな、仲良くしましょうよ。ね？","ENG":"Please, let's just all talk it out peacefully?","TWN":"大家不要打架好不好？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"저 계집애는 내 발 앞에 실탄까지 쐈단 말이야!","JPN":"あの小娘は俺の足の前に実弾まで撃ち込んだんだぞ！","ENG":"That brat shot bullets at my feet!","TWN":"那丫頭朝我開槍，子彈打到我腳前欸！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L41_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"쿨럭!!","JPN":"ゲホッ！！","ENG":"*Cough!!*","TWN":"咳咳！！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"으아악! 피, 피다!","JPN":"うわあっ！　ち、血だ！","ENG":"Aaack! B-blood!","TWN":"啊啊啊！血，是血！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L46_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"꺄악! 부사장님, 피가!","JPN":"きゃあっ！　副社長、血が！","ENG":"Kyaaah! Vice President...! You're coughing blood!","TWN":"啊！副總，你咳出血了！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L48_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"저 용병들이 회사를 휘젓고 다닌 스트레스로 부상이 덧났군요. 미안해요, 하나 씨.","JPN":"あの傭兵たちが会社をかき回したストレスで傷が悪化しました。すみません、ナカシマさん。","ENG":"My wounds have not healed properly because of the stress of being attacked by these mercenaries. I'm sorry, Miss Kim.","TWN":"這些傭兵來公司搗亂，害我壓力大到病情加重。荷娜，對不起。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"세상에 어떻게 그런……. 여러분들 정말 너무하시네요……!","JPN":"まあ、そんな……みなさん、本当にひどいですね……！","ENG":"Oh my gosh... You terrible people...!","TWN":"怎麼可以這樣……你們真的太過分了……！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L1_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"아니야! 아니라고!","JPN":"違う！　違うって！","ENG":"No! We didn't do that!","TWN":"誤會誤會，我們沒有！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그래요. 인정하기 싫으시면 재판까지 가죠.","JPN":"そうですか。認めたくないなら、裁判で争いましょう。","ENG":"Very well. If you won't admit it, we shall see you in court.","TWN":"是嗎？既然你們不承認，那只好法院見了。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"재, 재판이라니?","JPN":"さ、裁判？","ENG":"C-court?!","TWN":"法，法院見？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"저희 회사가 입은 물질적인 피해, 그리고 직원들이 입은 정신적인 피해.","JPN":"会社が受けた物質的被害、そして社員たちが受けた精神的被害。","ENG":"For damages done to the company, and the mental distress you inflicted on our employees.","TWN":"我們公司的財物損失，還有員工的心理創傷，"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그쪽 회사 법무팀과 법원에서 얘기하겠다는 뜻입니다.","JPN":"そちらの会社の法務チームと法廷で話し合いましょうという意味です。","ENG":"I will have a talk with your legal team in court.","TWN":"這些我都會在法院向貴司法務部陳述。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"물론 그쪽의 처지는 소송 결과와 아무 관련 없겠지만요.","JPN":"もちろん、そちらの処遇は訴訟の結果と何の関係もないでしょうが。","ENG":"Of course, I could care less about what happens to you after the lawsuit has been resolved.","TWN":"不過你們的下場與訴訟結果無關。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이런 쉬운 일 때문에 회사를 소송에 휘말려들게 했다는 이유라면……","JPN":"こんな簡単なことのために会社を訴訟に巻き込んだという理由でしたら……","ENG":"But getting sued for something as easy as this job...","TWN":"這麼簡單的事也辦不好，還讓公司捲入官司……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"뒤는 굳이 제 입으로 얘기할 필요 없겠군요.","JPN":"その後はあえて私が話すまでもありませんね。","ENG":"I believe I don't have to spell out what happens next, no?","TWN":"下場會如何應該不用我說吧？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"미리 말씀드리는데 저는 중환자입니다. 제 기침에서 나온 피는 소품이 아니에요.","JPN":"あらかじめ申し上げておきますが、私は重病人です。私の咳から出た血は、小道具ではありません。","ENG":"Just so you know, I am in critical health. My coughing up blood is not for show.","TWN":"話先說在前頭，我可是重症患者，我咳出來的血可不是道具。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"이, 이이, 이 공갈협박범 놈들……!","JPN":"こ、ここ、このゆすり屋め……！","ENG":"Y-you blackmailing crooks...!","TWN":"你，你，你，你這是在威脅恐嚇我嗎……！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"악마다, 악마…….","JPN":"悪魔だ、悪魔……","ENG":"Devil... You're the devil...","TWN":"哇，是魔鬼……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"회사를 어떻게 지켰는지 감이 잡히는군.","JPN":"どうやって会社を守ってきたのか、想像がつくな。","ENG":"Now I see how you were able to protect this company.","TWN":"原來她是這樣在保護公司的。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"섭섭한 말씀을. 누구 덕분에 세상 사는 법을 배웠는데요.","JPN":"ずいぶんなお言葉ですね。誰のおかげで世の中を渡り歩く術を覚えたと思っているのですか？","ENG":"That's harsh. Who do you believe taught me all of this, hmm?","TWN":"怎麼這樣說？也不想想是托誰的福，我才學會如何在這個世界生存的。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"진흙탕 싸움에 뛰어들기 싫으시면 관리국의 누구에게 지시 받은 건지 밝히도록 하세요.","JPN":"泥沼の争いに関わりたくなければ、管理局の誰から指示されたのか話しなさい。","ENG":"I suggest you tell us who in the Administration issued this order, if you do not want to be involved further in this mess.","TWN":"要是不想惹得一身腥，就快點說到底是管理局的誰指使你們的。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"넘버링 태스크포스를 상대로 이런 짓을 지시할 분이라면 꽤나 높으신 분이겠죠.","JPN":"ナンバリングタスクフォースを相手にこんなことを指示する方なら、相当偉い人でしょうね。","ENG":"Being able to go against a numbered TASKFORCE means that it is someone high up the ladder.","TWN":"對手可是這麼多的特遣勢力，可以下這種指令的人肯定是高層吧？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"큭…….","JPN":"くっ……","ENG":"Kgh...","TWN":"唔……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"당신이 그걸 알아서 뭘 어쩔 셈인데? 안다고 뭐가 달라져?","JPN":"それをあんたが知ってどうするつもりだ？　知ったところで何も変わらねえよ。","ENG":"What are you gonna do even if I tell you? Nothing's gonna change!","TWN":"你知道後要做什麼？可以改變什麼嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"왜, 소문의 그 잘난 관리자 나리에게 부탁이라도 하시려나?","JPN":"何だよ、ウワサのそのすごい管理者の旦那にお願いでもしようってのか？","ENG":"What? Are you gonna ask that rumored Administrator for help, hmm?","TWN":"怎麼？難不成你想去拜託那個偉大的管理者嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"자랑은 아니지만 저는 관리국에서 발이 꽤 넓은 편입니다.","JPN":"自慢ではありませんが、私は管理局で結構顔が広い方なのです。","ENG":"I do not like to boast, but my ties to the Administration are deeper than you think.","TWN":"不是我在說，我在管理局的人脈還蠻廣的。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"어딜 놀러 다니는지 항상 부재 중인 최고 관리자를 제외하더라도…….","JPN":"どこで遊びまわっているのやら、いつも留守にしている最高管理者を除いても……","ENG":"Even if I exclude the Supreme Administrator who always seems to be out of the office...","TWN":"就算沒有一天到晚不見人影的管理者……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"크흠. 이쪽 보고 말하지 말게.","JPN":"コホン。こちらを見ながら話さないでくれ。","ENG":"Ahem. Please don't say that while looking this way.","TWN":"咳咳，可以不要看著我說嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"2급 관리자, <color=#ffd34c>시니어</color>들과도 일면식이 있으니까요.","JPN":"2級管理者、<color=#ffd34c>シニア</color>たちとも面識がありますから。","ENG":"I also know quite a few of the Class 2 Administrators, <color=#ffd34c>Seniors</color>, as they're called.","TWN":"我和2級管理者，<color=#ffd34c>Senior</color>也有一面之緣。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"시니어들과……?","JPN":"シニアたちと……？","ENG":"Even the Seniors...?","TWN":"Senior……？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"젠장, 허세 작작 부려! 조작 영상이 떠도는 걸로도 모자라 이제는 시니어라고?","JPN":"くそ、はったりもいい加減にしろ！　偽動画の次はシニアだぁ？","ENG":"Enough with your bluffing! First, you go upload faked videos and now you claim to know Seniors?!","TWN":"可惡！少在那邊嚇唬人！散布造假影片還不夠，現在還想拿Senior來壓我們？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L36_1","type":"dialog","speaker":"PMC_SUMMER_NULL_L","text":{"KOREA":"이런 작은 회사에 그게 가당키나 하냐!","JPN":"こんな小さな会社にそんなことがあり得るか！","ENG":"Like that's even possible for a puny company like this one!","TWN":"這種小公司怎麼可能認識高層！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PMC_SUMMER_NULL_L","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"못 믿겠으면 사실인지 거짓인지 확인시켜 드리죠.","JPN":"信じられないというなら、本当か嘘か確認してみますか。","ENG":"If you do not believe me, I guess I will have to prove it then.","TWN":"不信的話，我可以讓你們確認一下是真是假。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CONDUCT_HARMONY_WEDDING_QM","text":{"KOREA":"아니. 굳이 그럴 필요 없어.","JPN":"いや。その必要はない。","ENG":"No. There will be no need for that.","TWN":"不用，沒那個必要。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"음? 이 목소리는…….","JPN":"うん？　この声は……","ENG":"Hmm? I know that voice...","TWN":"嗯？這個聲音是……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"르네?","JPN":"ルネ？","ENG":"Renée?","TWN":"芮妮？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그래. 공적으로는 오랜만에 보네, 이수연 부사장.","JPN":"そうだ。仕事で会うのは久しぶりだな、カナミ副社長。","ENG":"Yeah. It's been a while since we met officially, Vice President Lee Sooyeon.","TWN":"是我，李秀妍副總，好久沒在工作場合中碰面了。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"지시를 내린 건 나야.","JPN":"指示を出したのはこの私だ。","ENG":"I'm the one who issued the order.","TWN":"指使他們的人就是我。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"너와 일면식이 있는 그 시니어가 말이지.","JPN":"あなたと面識のあるシニア、のね。","ENG":"The \\"Senior acquaintance\\" of yours.","TWN":"就是那個和你有過一面之緣的Senior。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};